import React, { useState } from "react";

export default function GoalDetailsScreen({ goal, onBack, onAddFunds, onWithdraw, onUpdateGoal }) {
  const [current, setCurrent] = useState(goal.current);

  const handleAddFunds = (amount) => {
    if (amount <= 0) return;
    const updatedGoal = { ...goal, current: current + amount };
    setCurrent(updatedGoal.current);
    onUpdateGoal(updatedGoal);
  };

  const handleWithdraw = (amount) => {
    if (amount <= 0 || amount > current) return;
    const updatedGoal = { ...goal, current: current - amount };
    setCurrent(updatedGoal.current);
    onUpdateGoal(updatedGoal);
  };

  return (
    <div className="p-6 min-h-screen flex flex-col">
      <button onClick={onBack} className="mb-6 text-gray-500">
        ← Back
      </button>

      <h2 className="text-2xl font-bold mb-4">{goal.title}</h2>

      <p className="mb-4">
        Progress: ${current.toLocaleString()} / ${goal.target.toLocaleString()} (
        {Math.round((current / goal.target) * 100)}%)
      </p>

      <div className="flex gap-4 mb-6">
        <button
          onClick={() => onAddFunds(goal)}
          className="flex-1 py-3 bg-emerald-500 text-white rounded-xl font-bold"
        >
          Add Funds
        </button>
        <button
          onClick={() => onWithdraw(goal)}
          className="flex-1 py-3 bg-red-500 text-white rounded-xl font-bold"
        >
          Withdraw
        </button>
      </div>

      <div className="h-4 w-full bg-gray-200 rounded-full mb-2 overflow-hidden">
        <div
          className={`h-full ${goal.color} rounded-full transition-all duration-500`}
          style={{ width: `${(current / goal.target) * 100}%` }}
        />
      </div>

      <p className="text-xs text-gray-400">
        {Math.round((current / goal.target) * 100)}% completed
      </p>
    </div>
  );
}
